function escText(s: unknown): string {
  return String(s ?? '')
    .split('&').join('&amp;')
    .split('<').join('&lt;')
    .split('>').join('&gt;')
    .split('"').join('&quot;');
}
function escAttr(s: unknown): string {
  return String(s ?? '')
    .split('<').join('&lt;')
    .split('>').join('&gt;')
    .split('"').join('&quot;');
}

/**
 * Rend un email VMD pret a envoyer (subject + preheader + html).
 * {{prenom}} : present -> ' Prenom' (espace inclus, 'Bonjour Prenom,') ; vide -> '' ('Bonjour,').
 */
export function renderVmdEmail(
  id: VmdEmailId,
  vars: VmdEmailVars = {},
): { subject: string; preheader: string; html: string } {
  const def = VMD_EMAIL_DEFS[id];
  const prenom = String(vars.prenom ?? '').trim();
  const map: Record<string, string> = {
    prenom: prenom ? ' ' + escText(prenom) : '',
    lien_desinscription: escAttr(vars.lien_desinscription ?? 'mailto:contact@verifiermondevis.fr?subject=Désinscription'),
    lien_mentions: escAttr(vars.lien_mentions ?? 'https://www.verifiermondevis.fr/mentions-legales'),
  };
  const html = TEMPLATES[id].replace(/\{\{(\w+)\}\}/g, (m, k) => (k in map ? map[k] : m));
  return { subject: def.subject, preheader: def.preheader, html };
}
